module bin2gray(
    input [3:0] obf_bin_in,

    output reg [3:0] gray_out
);

always @(*)
begin
    gray_out[3] = obf_bin_in[3];
    gray_out[2] = obf_bin_in[3] ^ obf_bin_in[2];
    gray_out[1] = obf_bin_in[2] ^ obf_bin_in[1];
    gray_out[0] = obf_bin_in[1] ^ obf_bin_in[0];
end

endmodule
